<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">n_total</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(layout)              </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># total Nparams</span></span>
